	public static RuleGuard noMinusJoinPrefixPushdown(String differenceCaptureName) {
		return capture -> {
			IrNode difference = capture.node(differenceCaptureName);
			if (difference.op() != IrOp.DIFFERENCE || difference.inputs().size() != 2) {
				return RuleGuard.GuardResult.ok("no minus prefix pushdown");
			}
			if (!prefixPushdownCorrelatableMinusRhs(capture.ir(), difference.inputs().get(1))) {
				return RuleGuard.GuardResult.ok("minus RHS not prefix-pushable");
			}
			IrNode left = capture.ir().node(difference.inputs().get(0));
			IrNode right = capture.ir().node(difference.inputs().get(1));
			IrNode join = minusJoinInput(capture.ir(), left);
			if (join == null) {
				return RuleGuard.GuardResult.ok("no minus prefix join");
			}
			BindingMask shared = left.bindings().possible().intersect(right.bindings().possible());
			if (shared.isEmpty()) {
				return RuleGuard.GuardResult.ok("no minus shared variables");
			}
			IrNode leftPrefix = capture.ir().node(join.inputs().get(0));
			IrNode rightPrefix = capture.ir().node(join.inputs().get(1));
			boolean leftPushdown = canPushMinusIntoJoinPrefix(leftPrefix, rightPrefix, right, shared);
			boolean rightPushdown = canPushMinusIntoJoinPrefix(rightPrefix, leftPrefix, right, shared);
			return leftPushdown || rightPushdown
					? RuleGuard.GuardResult.fail("minus prefix pushdown available before physical implementation")
					: RuleGuard.GuardResult.ok("no minus prefix pushdown");
		};
	}

